current_user = users_db[1]


def require_admin(f):
    @wraps(f)
    def wrapper(*args, **kwargs):
        if not current_user or current_user.get("role") != "admin":
            return jsonify({"error": "forbidden"}), 403
        return f(*args, **kwargs)
    return wrapper


def validate_user_update(data):
    errors = {}

    if not isinstance(data, dict):
        return {"error": "invalid json payload"}, 400

    if "email" in data:
        if not isinstance(data["email"], str) or "@" not in data["email"]:
            errors["email"] = "invalid email"

    if "username" in data:
        if not isinstance(data["username"], str) or not data["username"].strip():
            errors["username"] = "invalid username"

    if "role" in data:
        if data["role"] not in ALLOWED_ROLES:
            errors["role"] = f"must be one of: {sorted(ALLOWED_ROLES)}"

    if "account_status" in data:
        if data["account_status"] not in ALLOWED_ACCOUNT_STATUS:
            errors["account_status"] = f"must be one of: {sorted(ALLOWED_ACCOUNT_STATUS)}"

    if "subscription_tier" in data:
        if data["subscription_tier"] not in ALLOWED_SUBSCRIPTION_TIERS:
            errors["subscription_tier"] = f"must be one of: {sorted(ALLOWED_SUBSCRIPTION_TIERS)}"

    allowed_fields = {"email", "username", "role", "account_status", "subscription_tier"}
    unknown_fields = set(data.keys()) - allowed_fields
    if unknown_fields:
        errors["unknown_fields"] = sorted(unknown_fields)

    return (errors, 400) if errors else (None, None)


@app.route("/api/users/<int:user_id>", methods=["PUT"])
@require_admin
def update_user(user_id):
    user = users_db.get(user_id)
    if not user:
        return jsonify({"error": "user not found"}), 404

    data = request.get_json(silent=True)
    errors, status = validate_user_update(data)
    if errors:
        return jsonify({"errors": errors}), status

    if "email" in data:
        user["email"] = data["email"].strip()
